toolArgs.file_text:
@page "/catalog"
@using sv_d77905286dea479b9187618e70d92d89.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    <div class="col-md-3">
        <CatalogFilters Categories="_categories"
                        OnApply="HandleApplyFilters"
                        OnClear="HandleClearFilters" />
    </div>

    <div class="col-md-9">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <p class="mt-2 text-muted">Loading products…</p>
            </div>
        }
        else if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
                <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            Page="_page"
                            PageSize="PageSize"
                            TotalCount="_totalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_products"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_page"
                               TotalPages="_totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private List<Product> _products = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProducts();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await LoadProducts();
    }

    private async Task HandleClearFilters()
    {
        _filter = new ProductFilter(null, null, null, false);
        _page = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }
}

